const express=require('express'),multer=require('multer'),cors=require('cors'),morgan=require('morgan'),path=require('path'),fs=require('fs'),crypto=require('crypto'),Database=require('better-sqlite3'),helmet=require('helmet'),rateLimit=require('express-rate-limit');
const app=express(),PORT=process.env.PORT||3000;
const UPLOADS_DIR=path.join(__dirname,'public','uploads'),DB_DIR=path.join(__dirname,'database'),DB_PATH=path.join(DB_DIR,'fueltrack.db');
const ALLOWED_IMG_EXT=new Set(['.jpg','.jpeg','.png','.webp','.gif','.bmp']);
[UPLOADS_DIR,DB_DIR].forEach(d=>{if(!fs.existsSync(d))fs.mkdirSync(d,{recursive:true})});
let db;
function run(sql,p=[]){db.prepare(sql).run(...p)}
function all(sql,p=[]){return db.prepare(sql).all(...p)}
function get(sql,p=[]){return db.prepare(sql).get(...p)||null}
const uid=()=>crypto.randomUUID();
const hashPass=(pass,salt)=>{salt=salt||crypto.randomBytes(16).toString('hex');const h=crypto.pbkdf2Sync(pass,salt,100000,64,'sha512').toString('hex');return{salt,hash:h}};
const safeFn=fn=>{const base=path.basename(fn);if(!base||base.startsWith('.')||base!==fn)return null;return base;};
const safeInt=(v,def=50,max=500)=>{const n=parseInt(v);return isNaN(n)?def:Math.min(Math.max(n,1),max)};
const safeOffset=(v)=>{const n=parseInt(v);return isNaN(n)||n<0?0:n;};
const validatePassword=(p)=>{if(!p||p.length<8)return'Senha deve ter no mínimo 8 caracteres';return null;};
const safeFilePath=(filename)=>{const resolved=path.resolve(UPLOADS_DIR,filename);if(!resolved.startsWith(UPLOADS_DIR))return null;return resolved;};
const KM_SERVICE_TYPES=[{key:'oleo',label:'Oleo'},{key:'correia_dentada',label:'Correia Dentada'},{key:'pneus',label:'Pneus'},{key:'freios',label:'Freios'}];
const normalizeKmService=s=>String(s||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^a-z0-9]+/g,'_').replace(/^_+|_+$/g,'');
const validMonth=m=>/^\d{4}-\d{2}$/.test(m||'')?m:new Date().toISOString().slice(0,7);
const toNum=v=>{const n=parseFloat(v);return isNaN(n)?0:n;};
const normalizeDiscountType=t=>String(t||'').toLowerCase()==='percentual'?'percentual':'valor';
const normalizeNotaItems=items=>(Array.isArray(items)?items:[]).map(it=>({descricao:String(it?.descricao||'').trim().slice(0,300),quantidade:Math.max(toNum(it?.quantidade)||1,0),valor:Math.max(toNum(it?.valor),0)})).filter(it=>it.descricao&&it.quantidade>0);
const MATERIAL_STATUS=new Set(['orcamento','agendado','entregue','cancelado']);
const normalizeMaterialStatus=s=>MATERIAL_STATUS.has(String(s||''))?String(s):'orcamento';
function calcNotaTotals(subtotal,desconto,descontoTipo){
const tipo=normalizeDiscountType(descontoTipo),raw=Math.max(toNum(desconto),0),descontoAplicado=tipo==='percentual'?Math.min(subtotal*(raw/100),subtotal):Math.min(raw,subtotal),total=Math.max(subtotal-descontoAplicado,0);
return{desconto_tipo:tipo,desconto:raw,desconto_aplicado:descontoAplicado,total};
}
function enrichMaterialRow(row){
const quantidade=toNum(row.quantidade),custoUnit=toNum(row.valor_custo_unit),vendaUnit=toNum(row.valor_venda_unit),freteCusto=toNum(row.frete_custo),freteCobrado=toNum(row.frete_cobrado),taxas=toNum(row.taxas),subtotalCusto=quantidade*custoUnit,subtotalVenda=quantidade*vendaUnit,totalCusto=subtotalCusto+freteCusto+taxas,totalVenda=subtotalVenda+freteCobrado,lucro=totalVenda-totalCusto,margem=totalVenda>0?(lucro/totalVenda)*100:0;
return{...row,quantidade,valor_custo_unit:custoUnit,valor_venda_unit:vendaUnit,frete_custo:freteCusto,frete_cobrado:freteCobrado,taxas,subtotal_custo:subtotalCusto,subtotal_venda:subtotalVenda,total_custo:totalCusto,total_venda:totalVenda,lucro,margem_percentual:margem};
}
function collectVehicleKmPoints(vid){
const pts=[];
all("SELECT data AS d,hodometro AS km FROM abastecimentos WHERE veiculo_id=? AND hodometro>0",[vid]).forEach(r=>pts.push({data:r.d,km:+r.km||0}));
all("SELECT data AS d,km FROM checklists WHERE veiculo_id=? AND km>0",[vid]).forEach(r=>pts.push({data:r.d,km:+r.km||0}));
all("SELECT data_saida AS d,km_saida AS km FROM transferencias WHERE veiculo_id=? AND km_saida>0",[vid]).forEach(r=>pts.push({data:r.d,km:+r.km||0}));
all("SELECT data_retorno AS d,km_retorno AS km FROM transferencias WHERE veiculo_id=? AND data_retorno!='' AND km_retorno>0",[vid]).forEach(r=>pts.push({data:r.d,km:+r.km||0}));
all("SELECT data AS d,km_atual AS km FROM manutencoes WHERE veiculo_id=? AND km_atual>0",[vid]).forEach(r=>pts.push({data:r.d,km:+r.km||0}));
all("SELECT data AS d,km_horimetro AS km FROM notas_servico WHERE veiculo_id=? AND km_horimetro>0",[vid]).forEach(r=>pts.push({data:r.d,km:+r.km||0}));
return pts.filter(p=>p.data&&p.km>0).sort((a,b)=>String(a.data).localeCompare(String(b.data))||a.km-b.km);}
function buildKmPanelRow(v,mes,allControls){
const pts=collectVehicleKmPoints(v.id),monthPts=pts.filter(p=>String(p.data).slice(0,7)===mes),prevPts=pts.filter(p=>String(p.data).slice(0,7)<mes),currentKm=pts.length?pts[pts.length-1].km:(+v.km_ini||0),prevKm=prevPts.length?prevPts[prevPts.length-1].km:null,firstMonthKm=monthPts[0]?.km??null,lastMonthKm=monthPts[monthPts.length-1]?.km??null;
let monthStart=prevKm;
if(monthStart==null&&monthPts.length>1)monthStart=firstMonthKm;
if(monthStart==null&&(+(v.km_ini||0))>0)monthStart=+v.km_ini;
const monthEnd=lastMonthKm,monthTotal=monthEnd!=null?Math.max(monthEnd-(monthStart??0),0):0;
const controlMap=new Map((allControls||[]).filter(c=>c.veiculo_id===v.id).map(c=>[c.servico,c]));
const controles=KM_SERVICE_TYPES.map(t=>{const c=controlMap.get(t.key),previsao=+c?.previsao_km||0,restante=previsao?Math.round(previsao-currentKm):null,status=!previsao?'vazio':currentKm>=previsao?'vencido':restante<=1000?'atencao':'ok';return{servico:t.key,label:t.label,previsao_km:previsao||null,atual_km:currentKm||0,restante_km:restante,status,obs:c?.obs||''};});
return{id:v.id,placa:v.placa,nome:v.nome,marca:v.marca,modelo:v.modelo,tipo:v.tipo,km_atual:currentKm||0,km_inicial_mes:monthStart,km_final_mes:monthEnd,km_rodado_mes:monthTotal,leituras_mes:monthPts.length,controles};}

