db.exec(`CREATE TABLE IF NOT EXISTS checklist_item_fotos(id TEXT PRIMARY KEY,checklist_item_id TEXT NOT NULL,filename TEXT NOT NULL,criado_em TEXT DEFAULT(datetime('now','localtime')))`);
