db.exec(`CREATE TABLE IF NOT EXISTS manutencoes(id TEXT PRIMARY KEY,veiculo_id TEXT NOT NULL,data TEXT NOT NULL,tipo TEXT DEFAULT 'preventiva',descricao TEXT DEFAULT '',oficina TEXT DEFAULT '',valor REAL DEFAULT 0,km_atual REAL DEFAULT 0,proxima_km REAL DEFAULT 0,proxima_data TEXT DEFAULT '',status TEXT DEFAULT 'concluido',obs TEXT DEFAULT '',criado_em TEXT DEFAULT(datetime('now','localtime')))`);
