function authMiddleware(req,res,next){const token=req.headers['authorization']?.replace('Bearer ','');if(!token)return res.status(401).json({error:'Token obrigatório'});const s=get("SELECT s.*,u.nome,u.login,u.perfil,u.email,u.id AS uid,u.motorista_id FROM sessoes s JOIN usuarios u ON u.id=s.usuario_id WHERE s.token=? AND u.ativo=1",[token]);if(!s)return res.status(401).json({error:'Sessão inválida'});if(new Date(s.expira_em)<new Date()){run("DELETE FROM sessoes WHERE token=?",[token]);return res.status(401).json({error:'Expirada'})}req.user=s;run("UPDATE sessoes SET expira_em=? WHERE token=?",[new Date(Date.now()+8*3600000).toISOString(),token]);next()}
function adminOnly(req,res,next){if(req.user.perfil!=='admin')return res.status(403).json({error:'Admin only'});next()}
function audit(req,acao,entidade,entidade_id,detalhes){try{run("INSERT INTO auditoria(id,usuario_id,usuario_login,acao,entidade,entidade_id,detalhes,ip)VALUES(?,?,?,?,?,?,?,?)",[uid(),req.user?.uid||'',req.user?.login||'',acao,entidade||'',entidade_id||'',JSON.stringify(detalhes||{}).slice(0,2000),(req.ip||'').slice(0,60)])}catch(e){}}
function buildUserPayload(u){const motorista=u.motorista_id?get("SELECT id,nome,cnh,telefone FROM motoristas WHERE id=?",[u.motorista_id]):null;return{id:u.id||u.uid,nome:u.nome,login:u.login,perfil:u.perfil,email:u.email,motorista_id:u.motorista_id||'',motorista}}

// AUTH — rate limiting (5 tentativas por 2 min por IP, bloqueio exponencial)
const loginAttempts=new Map();
function checkRateLimit(ip){const now=Date.now();const entry=loginAttempts.get(ip)||{count:0,resetAt:now+120000,lockUntil:0};if(now<entry.lockUntil)return false;if(now>entry.resetAt){entry.count=0;entry.resetAt=now+120000;entry.lockUntil=0;}entry.count++;loginAttempts.set(ip,entry);if(entry.count>5){entry.lockUntil=now+Math.min(entry.count*60000,600000);return false;}return true;}
setInterval(()=>{const now=Date.now();for(const[k,v]of loginAttempts)if(now>v.resetAt&&now>v.lockUntil)loginAttempts.delete(k);},120000);
// Limpeza de sessões expiradas a cada hora
setInterval(()=>{try{run("DELETE FROM sessoes WHERE expira_em < datetime('now','localtime')");}catch(e){}},3600000);

app.post('/api/auth/login',(req,res)=>{if(!checkRateLimit(req.ip))return res.status(429).json({error:'Muitas tentativas. Aguarde alguns minutos.'});const{login,senha}=req.body;if(!login||!senha)return res.status(400).json({error:'Login e senha obrigatórios'});const u=get("SELECT * FROM usuarios WHERE login=? AND ativo=1",[login]);if(!u)return res.status(401).json({error:'Usuário ou senha inválidos'});const{hash}=hashPass(senha,u.senha_salt);if(hash!==u.senha_hash)return res.status(401).json({error:'Usuário ou senha inválidos'});run("DELETE FROM sessoes WHERE usuario_id=? AND expira_em<datetime('now','localtime')",[u.id]);const token=crypto.randomBytes(32).toString('hex');run("INSERT INTO sessoes(token,usuario_id,expira_em)VALUES(?,?,?)",[token,u.id,new Date(Date.now()+8*3600000).toISOString()]);try{run("INSERT INTO auditoria(id,usuario_id,usuario_login,acao,entidade,ip)VALUES(?,?,?,?,?,?)",[uid(),u.id,u.login,'login','sessao',(req.ip||'').slice(0,60)])}catch(e){}res.json({token,user:buildUserPayload(u)})});
app.post('/api/auth/logout',(req,res)=>{const t=req.headers['authorization']?.replace('Bearer ','');if(t)run("DELETE FROM sessoes WHERE token=?",[t]);res.json({ok:true})});
app.get('/api/auth/me',authMiddleware,(req,res)=>res.json(buildUserPayload(req.user)));
app.put('/api/auth/senha',authMiddleware,(req,res)=>{const{senha_atual,nova_senha}=req.body;if(!senha_atual||!nova_senha)return res.status(400).json({error:'Campos obrigatórios'});const pwErr=validatePassword(nova_senha);if(pwErr)return res.status(400).json({error:pwErr});const u=get("SELECT * FROM usuarios WHERE id=?",[req.user.uid]);const{hash:ch}=hashPass(senha_atual,u.senha_salt);if(ch!==u.senha_hash)return res.status(401).json({error:'Senha atual incorreta'});const{salt,hash}=hashPass(nova_senha);run("UPDATE usuarios SET senha_hash=?,senha_salt=? WHERE id=?",[hash,salt,req.user.uid]);res.json({ok:true})});

// USERS
const PERFIS=new Set(['admin','operador','operador_maquina']);
const normalizePerfil=p=>PERFIS.has(p)?p:'operador';
app.get('/api/usuarios',authMiddleware,adminOnly,(_,res)=>res.json(all("SELECT u.id,u.nome,u.email,u.login,u.perfil,u.ativo,u.criado_em,u.motorista_id,m.nome AS motorista_nome FROM usuarios u LEFT JOIN motoristas m ON m.id=u.motorista_id ORDER BY u.nome")));
app.post('/api/usuarios',authMiddleware,adminOnly,(req,res)=>{const{nome,email,login,senha,perfil,motorista_id}=req.body;if(!nome||!login||!senha)return res.status(400).json({error:'Nome,login,senha'});const pwErr=validatePassword(senha);if(pwErr)return res.status(400).json({error:pwErr});const np=normalizePerfil(perfil);if(np==='operador_maquina'&&!motorista_id)return res.status(400).json({error:'Operador de Máquina precisa estar vinculado a um motorista'});if(motorista_id&&!get("SELECT id FROM motoristas WHERE id=? AND ativo=1",[motorista_id]))return res.status(400).json({error:'Motorista inválido'});const{salt,hash}=hashPass(senha);const id=uid();try{run("INSERT INTO usuarios(id,nome,email,login,senha_hash,senha_salt,perfil,motorista_id)VALUES(?,?,?,?,?,?,?,?)",[id,nome,email||'',login,hash,salt,np,motorista_id||'']);audit(req,'criar','usuario',id,{login,perfil:np,motorista_id:motorista_id||''});res.json(get("SELECT u.id,u.nome,u.email,u.login,u.perfil,u.ativo,u.criado_em,u.motorista_id,m.nome AS motorista_nome FROM usuarios u LEFT JOIN motoristas m ON m.id=u.motorista_id WHERE u.id=?",[id]))}catch(e){res.status(400).json({error:e.message.includes('UNIQUE')?'Login já existe':'Erro ao criar usuário'})}});
app.put('/api/usuarios/:id',authMiddleware,adminOnly,(req,res)=>{const{nome,email,perfil,ativo,senha,motorista_id}=req.body;const np=normalizePerfil(perfil);const mid=motorista_id===undefined?get("SELECT motorista_id FROM usuarios WHERE id=?",[req.params.id])?.motorista_id||'':(motorista_id||'');if(np==='operador_maquina'&&!mid)return res.status(400).json({error:'Operador de Máquina precisa estar vinculado a um motorista'});if(mid&&!get("SELECT id FROM motoristas WHERE id=? AND ativo=1",[mid]))return res.status(400).json({error:'Motorista inválido'});run("UPDATE usuarios SET nome=?,email=?,perfil=?,ativo=?,motorista_id=? WHERE id=?",[nome||'',email||'',np,ativo!==undefined?ativo:1,mid,req.params.id]);if(senha){const pwErr=validatePassword(senha);if(pwErr)return res.status(400).json({error:pwErr});const{salt,hash}=hashPass(senha);run("UPDATE usuarios SET senha_hash=?,senha_salt=? WHERE id=?",[hash,salt,req.params.id])}audit(req,'editar','usuario',req.params.id,{perfil:np,motorista_id:mid,senha_alterada:!!senha});res.json(get("SELECT u.id,u.nome,u.email,u.login,u.perfil,u.ativo,u.criado_em,u.motorista_id,m.nome AS motorista_nome FROM usuarios u LEFT JOIN motoristas m ON m.id=u.motorista_id WHERE u.id=?",[req.params.id]))});
app.delete('/api/usuarios/:id',authMiddleware,adminOnly,(req,res)=>{if(req.params.id===req.user.uid)return res.status(400).json({error:'Não pode excluir a si mesmo'});const u=get("SELECT perfil,nome,login FROM usuarios WHERE id=?",[req.params.id]);if(!u)return res.status(404).json({error:'Usuário não encontrado'});if(u.perfil==='admin'){const outros=get("SELECT COUNT(*)AS n FROM usuarios WHERE perfil='admin' AND ativo=1 AND id!=?",[req.params.id])?.n||0;if(outros===0)return res.status(400).json({error:'Não pode excluir o único admin do sistema'})}run("DELETE FROM sessoes WHERE usuario_id=?",[req.params.id]);run("DELETE FROM usuarios WHERE id=?",[req.params.id]);audit(req,'excluir','usuario',req.params.id,{login:u.login,nome:u.nome});res.json({ok:true})});

