app.post('/api/alertas/verificar',authMiddleware,(req,res)=>{
const cfgDias=+(get("SELECT valor FROM config WHERE chave='alerta_dias_antecedencia'")?.valor||15);
const cfgKmCarro=+(get("SELECT valor FROM config WHERE chave='alerta_km_antecedencia'")?.valor||1000);
const cfgKmMoto=+(get("SELECT valor FROM config WHERE chave='alerta_km_antecedencia_moto'")?.valor||500);
const ms=all("SELECT m.*,v.placa,v.nome AS v_nome,v.tipo AS v_tipo FROM manutencoes m JOIN veiculos v ON v.id=m.veiculo_id WHERE v.ativo=1 AND(m.proxima_data!='' OR m.proxima_km>0)");
let created=0;const hoje=new Date();
ms.forEach(m=>{
const cfgKm=m.v_tipo==='moto'?cfgKmMoto:cfgKmCarro;
if(m.proxima_data){const diff=Math.ceil((new Date(m.proxima_data)-hoje)/864e5);if(diff<=cfgDias&&!get("SELECT id FROM alertas WHERE referencia_id=? AND tipo='manutencao_data' AND resolvido=0",[m.id])){const pri=diff<=0?'critica':diff<=5?'alta':'media';run("INSERT INTO alertas(id,veiculo_id,tipo,titulo,mensagem,prioridade,referencia_id)VALUES(?,?,?,?,?,?,?)",[uid(),m.veiculo_id,'manutencao_data',diff<=0?`[!] VENCIDA — ${m.placa}`:`Manutenção em ${diff}d — ${m.placa}`,`${m.descricao||m.tipo} em ${m.proxima_data}`,pri,m.id]);created++}}
if(m.proxima_km>0){const ka=get("SELECT MAX(hodometro)AS km FROM abastecimentos WHERE veiculo_id=? AND hodometro>0",[m.veiculo_id])?.km||m.km_atual||0;const rest=m.proxima_km-ka;if(rest<=cfgKm&&rest>-99999&&!get("SELECT id FROM alertas WHERE referencia_id=? AND tipo='manutencao_km' AND resolvido=0",[m.id])){const pri=rest<=0?'critica':rest<=300?'alta':'media';run("INSERT INTO alertas(id,veiculo_id,tipo,titulo,mensagem,prioridade,referencia_id)VALUES(?,?,?,?,?,?,?)",[uid(),m.veiculo_id,'manutencao_km',rest<=0?`[!] KM VENCIDO — ${m.placa}`:`${Math.round(rest)}km — ${m.placa}`,`${m.descricao||m.tipo} em ${m.proxima_km}km. Atual:${Math.round(ka)}km`,pri,m.id]);created++}}});
all("SELECT * FROM motoristas WHERE ativo=1 AND cnh_validade!=''").forEach(mot=>{const diff=Math.ceil((new Date(mot.cnh_validade)-hoje)/864e5);if(diff<=30&&!get("SELECT id FROM alertas WHERE referencia_id=? AND tipo='cnh' AND resolvido=0",[mot.id])){run("INSERT INTO alertas(id,veiculo_id,tipo,titulo,mensagem,prioridade,referencia_id)VALUES(?,?,?,?,?,?,?)",[uid(),'','cnh',diff<=0?`[!] CNH VENCIDA — ${mot.nome}`:`CNH ${diff}d — ${mot.nome}`,`Validade: ${mot.cnh_validade}`,diff<=0?'critica':diff<=7?'alta':'media',mot.id]);created++}});
res.json({created,message:`${created} alertas gerados`})});

app.post('/api/alertas/enviar-email',authMiddleware,adminOnly,async(req,res)=>{
const sh=get("SELECT valor FROM config WHERE chave='smtp_host'")?.valor,sp=get("SELECT valor FROM config WHERE chave='smtp_port'")?.valor||'587',su=get("SELECT valor FROM config WHERE chave='smtp_user'")?.valor,spw=get("SELECT valor FROM config WHERE chave='smtp_pass'")?.valor,ae=get("SELECT valor FROM config WHERE chave='alerta_email'")?.valor;
if(!sh||!su||!ae)return res.status(400).json({error:'Configure SMTP nas Configurações'});
try{const nm=require('nodemailer');const t=nm.createTransport({host:sh,port:+sp,secure:+sp===465,auth:{user:su,pass:spw}});const als=all("SELECT a.*,v.placa FROM alertas a LEFT JOIN veiculos v ON v.id=a.veiculo_id WHERE a.lido=0 AND a.resolvido=0");if(!als.length)return res.json({sent:false,message:'Nenhum pendente'});const emp=get("SELECT valor FROM config WHERE chave='empresa'")?.valor||'iLnet';let html=`<h2>Alertas — ${emp}</h2><table border=1 cellpadding=8 style="border-collapse:collapse;font-family:sans-serif"><tr style="background:#0a1e30;color:#fff"><th>Prioridade</th><th>Veículo</th><th>Alerta</th></tr>`;als.forEach(a=>{const c=a.prioridade==='critica'?'#e05252':a.prioridade==='alta'?'#f5923a':'#f5c842';html+=`<tr><td style="color:${c};font-weight:bold">${a.prioridade.toUpperCase()}</td><td>${a.placa||'—'}</td><td>${a.titulo}<br><small>${a.mensagem}</small></td></tr>`});html+='</table>';await t.sendMail({from:`"${emp}" <${su}>`,to:ae,subject:`[${emp}] ${als.length} alerta(s)`,html});res.json({sent:true,count:als.length})}catch(e){res.status(e.code==='MODULE_NOT_FOUND'?400:500).json({error:e.code==='MODULE_NOT_FOUND'?'npm install nodemailer':e.message})}});

const mkUpload=()=>multer({storage:multer.diskStorage({destination:(_,__,cb)=>cb(null,UPLOADS_DIR),filename:(_,f,cb)=>{const ext=(path.extname(f.originalname).toLowerCase()||'.jpg');if(!ALLOWED_IMG_EXT.has(ext))return cb(new Error('Extensão não permitida'));cb(null,Date.now()+'-'+crypto.randomBytes(8).toString('hex')+ext)}}),limits:{fileSize:10*1024*1024},fileFilter:(_,f,cb)=>{if(!f.mimetype.startsWith('image/'))return cb(new Error('Apenas imagens'));const ext=path.extname(f.originalname).toLowerCase();if(!ALLOWED_IMG_EXT.has(ext))return cb(new Error('Extensão não permitida: '+ext));cb(null,true)}});
const upload=mkUpload();

// VEÍCULOS
app.get('/api/veiculos',authMiddleware,(_,res)=>res.json(all("SELECT v.*,COUNT(a.id)AS total_abast,COALESCE(SUM(a.total),0)AS total_gasto,COALESCE(SUM(a.litros),0)AS total_litros,MAX(a.hodometro)AS hodometro_atual FROM veiculos v LEFT JOIN abastecimentos a ON a.veiculo_id=v.id WHERE v.ativo=1 GROUP BY v.id ORDER BY v.placa")));
app.post('/api/veiculos',authMiddleware,(req,res)=>{const{placa,nome,marca,modelo,ano,cor,combustivel,tanque,km_ini,tipo}=req.body;if(!placa)return res.status(400).json({error:'Placa'});const id=uid();try{run("INSERT INTO veiculos(id,placa,nome,marca,modelo,ano,cor,combustivel,tanque,km_ini,tipo)VALUES(?,?,?,?,?,?,?,?,?,?,?)",[id,placa.toUpperCase(),nome||'',marca||'',modelo||'',ano||null,cor||'',combustivel||'Gasolina',tanque||0,km_ini||0,tipo||'carro']);res.json(get('SELECT*FROM veiculos WHERE id=?',[id]))}catch(e){res.status(400).json({error:e.message.includes('UNIQUE')?'Placa já existe':'Erro ao criar veículo'})}});
app.put('/api/veiculos/:id',authMiddleware,(req,res)=>{const{placa,nome,marca,modelo,ano,cor,combustivel,tanque,km_ini,tipo}=req.body;run("UPDATE veiculos SET placa=?,nome=?,marca=?,modelo=?,ano=?,cor=?,combustivel=?,tanque=?,km_ini=?,tipo=? WHERE id=?",[placa?.toUpperCase()||'',nome||'',marca||'',modelo||'',ano||null,cor||'',combustivel||'',tanque||0,km_ini||0,tipo||'carro',req.params.id]);res.json(get('SELECT*FROM veiculos WHERE id=?',[req.params.id]))});
