app.get('/api/abastecimentos',authMiddleware,(req,res)=>{const{veiculo_id,combustivel,mes,busca}=req.query;const limit=safeInt(req.query.limit,200,500);const offset=safeOffset(req.query.offset);let sql="SELECT a.*,v.placa,v.nome AS v_nome,v.marca,v.modelo FROM abastecimentos a JOIN veiculos v ON v.id=a.veiculo_id WHERE v.ativo=1";const p=[];if(veiculo_id){sql+=' AND a.veiculo_id=?';p.push(veiculo_id)}if(combustivel){sql+=' AND a.combustivel=?';p.push(combustivel)}if(mes){sql+=" AND substr(a.data,1,7)=?";p.push(mes)}if(busca){sql+=' AND(v.placa LIKE? OR a.posto LIKE? OR a.combustivel LIKE?)';const b='%'+busca+'%';p.push(b,b,b)}sql+=' ORDER BY a.data DESC LIMIT ? OFFSET ?';p.push(limit,offset);const rows=all(sql,p);rows.forEach(r=>{const f=all('SELECT filename FROM fotos WHERE abastecimento_id=?',[r.id]);r.fotos=f.map(x=>'/uploads/'+x.filename);r.fotos_count=f.length});res.json(rows)});
