app.put('/api/abastecimentos/:id',authMiddleware,(req,res)=>{const{veiculo_id,data,combustivel,posto,litros,preco,total,hodometro,km_rodados,consumo,cheio,nota,obs}=req.body;run("UPDATE abastecimentos SET veiculo_id=?,data=?,combustivel=?,posto=?,litros=?,preco=?,total=?,hodometro=?,km_rodados=?,consumo=?,cheio=?,nota=?,obs=? WHERE id=?",[veiculo_id,data,combustivel,posto||'',+litros,+preco,+total,+hodometro||0,+km_rodados||0,+consumo||0,cheio?1:0,nota||'',obs||'',req.params.id]);res.json(get('SELECT*FROM abastecimentos WHERE id=?',[req.params.id]))});
