// SERVICE NOTES
app.get('/api/notas-servico',authMiddleware,(req,res)=>{const{veiculo_id,mes,busca}=req.query;const limit=safeInt(req.query.limit,100,2000);let sql="SELECT n.*,v.placa,v.nome AS v_nome,v.marca,v.modelo FROM notas_servico n LEFT JOIN veiculos v ON v.id=n.veiculo_id WHERE 1=1";const p=[];if(veiculo_id){sql+=' AND n.veiculo_id=?';p.push(veiculo_id)}if(mes){sql+=" AND substr(n.data,1,7)=?";p.push(mes)}if(busca){sql+=" AND (v.placa LIKE ? OR n.oficina LIKE ? OR n.numero LIKE ? OR EXISTS(SELECT 1 FROM nota_servico_itens i WHERE i.nota_id=n.id AND i.descricao LIKE ?))";const b='%'+busca+'%';p.push(b,b,b,b)}sql+=' ORDER BY n.data DESC,n.criado_em DESC LIMIT ?';p.push(limit);const rows=all(sql,p);rows.forEach(n=>{n.itens=all("SELECT * FROM nota_servico_itens WHERE nota_id=? ORDER BY criado_em,id",[n.id]);n.subtotal=n.itens.reduce((s,it)=>s+((+it.quantidade||0)*(+it.valor||0)),0);Object.assign(n,calcNotaTotals(n.subtotal,n.desconto,n.desconto_tipo));n.total_itens=n.itens.length});res.json(rows)});
app.get('/api/notas-servico/:id',authMiddleware,(req,res)=>{const n=get("SELECT * FROM notas_servico WHERE id=?",[req.params.id]);if(!n)return res.status(404).json({error:'404'});n.itens=all("SELECT * FROM nota_servico_itens WHERE nota_id=? ORDER BY criado_em,id",[n.id]);n.subtotal=n.itens.reduce((s,it)=>s+((+it.quantidade||0)*(+it.valor||0)),0);Object.assign(n,calcNotaTotals(n.subtotal,n.desconto,n.desconto_tipo));res.json(n)});
app.post('/api/notas-servico',authMiddleware,(req,res)=>{const{veiculo_id,data,km_horimetro,oficina,numero,desconto,desconto_tipo,obs}=req.body,itens=normalizeNotaItems(req.body.itens);if(!veiculo_id||!data||!itens.length)return res.status(400).json({error:'Veículo, data e itens obrigatórios'});const id=uid(),subtotal=itens.reduce((s,it)=>s+(it.quantidade*it.valor),0),totals=calcNotaTotals(subtotal,desconto,desconto_tipo);run("INSERT INTO notas_servico(id,veiculo_id,data,km_horimetro,oficina,numero,desconto,desconto_tipo,total,obs)VALUES(?,?,?,?,?,?,?,?,?,?)",[id,veiculo_id,data,toNum(km_horimetro),String(oficina||'').slice(0,200),String(numero||'').slice(0,80),totals.desconto,totals.desconto_tipo,totals.total,String(obs||'').slice(0,1000)]);itens.forEach(it=>run("INSERT INTO nota_servico_itens(id,nota_id,descricao,quantidade,valor)VALUES(?,?,?,?,?)",[uid(),id,it.descricao,it.quantidade,it.valor]));const row=get("SELECT * FROM notas_servico WHERE id=?",[id]);row.itens=all("SELECT * FROM nota_servico_itens WHERE nota_id=? ORDER BY criado_em,id",[id]);row.subtotal=subtotal;Object.assign(row,totals);res.json(row)});
app.put('/api/notas-servico/:id',authMiddleware,(req,res)=>{const exists=get("SELECT id FROM notas_servico WHERE id=?",[req.params.id]);if(!exists)return res.status(404).json({error:'404'});const{veiculo_id,data,km_horimetro,oficina,numero,desconto,desconto_tipo,obs}=req.body,itens=normalizeNotaItems(req.body.itens);if(!veiculo_id||!data||!itens.length)return res.status(400).json({error:'Veículo, data e itens obrigatórios'});const subtotal=itens.reduce((s,it)=>s+(it.quantidade*it.valor),0),totals=calcNotaTotals(subtotal,desconto,desconto_tipo);run("UPDATE notas_servico SET veiculo_id=?,data=?,km_horimetro=?,oficina=?,numero=?,desconto=?,desconto_tipo=?,total=?,obs=? WHERE id=?",[veiculo_id,data,toNum(km_horimetro),String(oficina||'').slice(0,200),String(numero||'').slice(0,80),totals.desconto,totals.desconto_tipo,totals.total,String(obs||'').slice(0,1000),req.params.id]);run("DELETE FROM nota_servico_itens WHERE nota_id=?",[req.params.id]);itens.forEach(it=>run("INSERT INTO nota_servico_itens(id,nota_id,descricao,quantidade,valor)VALUES(?,?,?,?,?)",[uid(),req.params.id,it.descricao,it.quantidade,it.valor]));const row=get("SELECT * FROM notas_servico WHERE id=?",[req.params.id]);row.itens=all("SELECT * FROM nota_servico_itens WHERE nota_id=? ORDER BY criado_em,id",[req.params.id]);row.subtotal=subtotal;Object.assign(row,totals);res.json(row)});
app.delete('/api/notas-servico/:id',authMiddleware,(req,res)=>{run("DELETE FROM nota_servico_itens WHERE nota_id=?",[req.params.id]);run("DELETE FROM notas_servico WHERE id=?",[req.params.id]);res.json({ok:true})});

