app.get('/api/entregas-materiais',authMiddleware,(req,res)=>{const{status,mes,busca,veiculo_id}=req.query;const limit=safeInt(req.query.limit,120,2000);let sql="SELECT e.*,v.placa,v.nome AS v_nome FROM entregas_materiais e LEFT JOIN veiculos v ON v.id=e.veiculo_id WHERE 1=1";const p=[];if(status){sql+=' AND e.status=?';p.push(status)}if(mes){sql+=" AND substr(e.data_pedido,1,7)=?";p.push(mes)}if(veiculo_id){sql+=' AND e.veiculo_id=?';p.push(veiculo_id)}if(busca){sql+=" AND (e.cliente LIKE ? OR e.material LIKE ? OR e.fornecedor LIKE ? OR e.cidade LIKE ? OR e.endereco LIKE ?)";const b='%'+busca+'%';p.push(b,b,b,b,b)}sql+=' ORDER BY e.data_pedido DESC,e.criado_em DESC LIMIT ?';p.push(limit);res.json(all(sql,p).map(enrichMaterialRow))});
