app.post('/api/entregas-materiais',authMiddleware,(req,res)=>{const{data_pedido,data_entrega,cliente,telefone,material,fornecedor,veiculo_id,motorista,quantidade,unidade,valor_custo_unit,valor_venda_unit,frete_custo,frete_cobrado,taxas,status,endereco,cidade,obs}=req.body;if(!data_pedido||!cliente||!material)return res.status(400).json({error:'Data, cliente e material sao obrigatorios'});const id=uid();run("INSERT INTO entregas_materiais(id,data_pedido,data_entrega,cliente,telefone,material,fornecedor,veiculo_id,motorista,quantidade,unidade,valor_custo_unit,valor_venda_unit,frete_custo,frete_cobrado,taxas,status,endereco,cidade,obs)VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)",[id,data_pedido,String(data_entrega||'').slice(0,10),String(cliente||'').trim().slice(0,200),String(telefone||'').trim().slice(0,40),String(material||'').trim().slice(0,160),String(fornecedor||'').trim().slice(0,200),String(veiculo_id||'').trim().slice(0,80),String(motorista||'').trim().slice(0,160),Math.max(toNum(quantidade),0),String(unidade||'Carrada').trim().slice(0,20)||'Carrada',Math.max(toNum(valor_custo_unit),0),Math.max(toNum(valor_venda_unit),0),Math.max(toNum(frete_custo),0),Math.max(toNum(frete_cobrado),0),Math.max(toNum(taxas),0),normalizeMaterialStatus(status),String(endereco||'').trim().slice(0,300),String(cidade||'').trim().slice(0,120),String(obs||'').trim().slice(0,1200)]);res.json(enrichMaterialRow(get("SELECT e.*,v.placa,v.nome AS v_nome FROM entregas_materiais e LEFT JOIN veiculos v ON v.id=e.veiculo_id WHERE e.id=?",[id])))});
app.put('/api/entregas-materiais/:id',authMiddleware,(req,res)=>{const exists=get("SELECT id FROM entregas_materiais WHERE id=?",[req.params.id]);if(!exists)return res.status(404).json({error:'404'});const{data_pedido,data_entrega,cliente,telefone,material,fornecedor,veiculo_id,motorista,quantidade,unidade,valor_custo_unit,valor_venda_unit,frete_custo,frete_cobrado,taxas,status,endereco,cidade,obs}=req.body;if(!data_pedido||!cliente||!material)return res.status(400).json({error:'Data, cliente e material sao obrigatorios'});run("UPDATE entregas_materiais SET data_pedido=?,data_entrega=?,cliente=?,telefone=?,material=?,fornecedor=?,veiculo_id=?,motorista=?,quantidade=?,unidade=?,valor_custo_unit=?,valor_venda_unit=?,frete_custo=?,frete_cobrado=?,taxas=?,status=?,endereco=?,cidade=?,obs=? WHERE id=?",[data_pedido,String(data_entrega||'').slice(0,10),String(cliente||'').trim().slice(0,200),String(telefone||'').trim().slice(0,40),String(material||'').trim().slice(0,160),String(fornecedor||'').trim().slice(0,200),String(veiculo_id||'').trim().slice(0,80),String(motorista||'').trim().slice(0,160),Math.max(toNum(quantidade),0),String(unidade||'Carrada').trim().slice(0,20)||'Carrada',Math.max(toNum(valor_custo_unit),0),Math.max(toNum(valor_venda_unit),0),Math.max(toNum(frete_custo),0),Math.max(toNum(frete_cobrado),0),Math.max(toNum(taxas),0),normalizeMaterialStatus(status),String(endereco||'').trim().slice(0,300),String(cidade||'').trim().slice(0,120),String(obs||'').trim().slice(0,1200),req.params.id]);res.json(enrichMaterialRow(get("SELECT e.*,v.placa,v.nome AS v_nome FROM entregas_materiais e LEFT JOIN veiculos v ON v.id=e.veiculo_id WHERE e.id=?",[req.params.id])))});
