function listMaquinasComStatus(){const ms=all("SELECT * FROM maquinas WHERE ativo=1 ORDER BY nome");const ativos=all("SELECT maquina_id,id,operador_nome,inicio FROM percursos WHERE status='em_andamento'");const map=new Map(ativos.map(p=>[p.maquina_id,p]));return ms.map(m=>{const p=map.get(m.id);return{...m,status_atual:p?'em_uso':'disponivel',percurso_ativo:p||null}})}
app.get('/api/maquinas',authMiddleware,(_,res)=>res.json(listMaquinasComStatus()));
app.get('/api/maquinas/:id',authMiddleware,(req,res)=>{const m=get("SELECT * FROM maquinas WHERE id=?",[req.params.id]);if(!m)return res.status(404).json({error:'404'});const p=get("SELECT * FROM percursos WHERE maquina_id=? AND status='em_andamento'",[req.params.id]);res.json({...m,status_atual:p?'em_uso':'disponivel',percurso_ativo:p||null})});
app.post('/api/maquinas',authMiddleware,adminOnly,(req,res)=>{const{nome,codigo,tipo,descricao,ano}=req.body;if(!nome||!codigo)return res.status(400).json({error:'Nome e código são obrigatórios'});const id=uid();try{run("INSERT INTO maquinas(id,nome,codigo,tipo,descricao,ano)VALUES(?,?,?,?,?,?)",[id,String(nome).trim().slice(0,160),String(codigo).trim().slice(0,60),String(tipo||'').trim().slice(0,80),String(descricao||'').trim().slice(0,500),ano?+ano:null]);audit(req,'criar','maquina',id,{nome,codigo});res.json(get("SELECT * FROM maquinas WHERE id=?",[id]))}catch(e){res.status(400).json({error:e.message.includes('UNIQUE')?'Código já existe':'Erro ao criar máquina'})}});
app.put('/api/maquinas/:id',authMiddleware,adminOnly,(req,res)=>{const{nome,codigo,tipo,descricao,ano,ativo}=req.body;if(!nome||!codigo)return res.status(400).json({error:'Nome e código são obrigatórios'});try{run("UPDATE maquinas SET nome=?,codigo=?,tipo=?,descricao=?,ano=?,ativo=? WHERE id=?",[String(nome).trim().slice(0,160),String(codigo).trim().slice(0,60),String(tipo||'').trim().slice(0,80),String(descricao||'').trim().slice(0,500),ano?+ano:null,ativo!==undefined?+!!ativo:1,req.params.id]);audit(req,'editar','maquina',req.params.id,{nome,codigo});res.json(get("SELECT * FROM maquinas WHERE id=?",[req.params.id]))}catch(e){res.status(400).json({error:e.message.includes('UNIQUE')?'Código já existe':'Erro ao editar máquina'})}});
app.delete('/api/maquinas/:id',authMiddleware,adminOnly,(req,res)=>{if(get("SELECT id FROM percursos WHERE maquina_id=? AND status='em_andamento'",[req.params.id]))return res.status(400).json({error:'Máquina com percurso em andamento. Encerre primeiro.'});run("UPDATE maquinas SET ativo=0 WHERE id=?",[req.params.id]);audit(req,'desativar','maquina',req.params.id,{});res.json({ok:true})});

// PERCURSOS
function fmtSeg(s){s=Math.max(0,+s||0);const h=Math.floor(s/3600),m=Math.floor((s%3600)/60),x=s%60;return String(h).padStart(2,'0')+':'+String(m).padStart(2,'0')+':'+String(x).padStart(2,'0')}
app.get('/api/percursos/ativo',authMiddleware,(req,res)=>{const p=get("SELECT * FROM percursos WHERE operador_id=? AND status='em_andamento'",[req.user.uid]);if(!p)return res.json(null);res.json({...p,duracao_seg_atual:Math.floor((Date.now()-new Date(p.inicio).getTime())/1000)})});
app.post('/api/percursos/iniciar',authMiddleware,(req,res)=>{const{maquina_id,lat,lng,endereco}=req.body;if(!maquina_id)return res.status(400).json({error:'Selecione uma máquina'});const m=get("SELECT * FROM maquinas WHERE id=? AND ativo=1",[maquina_id]);if(!m)return res.status(404).json({error:'Máquina não encontrada'});if(get("SELECT id FROM percursos WHERE operador_id=? AND status='em_andamento'",[req.user.uid]))return res.status(409).json({error:'Você já possui um percurso em andamento'});if(get("SELECT id FROM percursos WHERE maquina_id=? AND status='em_andamento'",[maquina_id]))return res.status(409).json({error:'Esta máquina já está em uso'});const motId=req.user.motorista_id||'';const motNome=motId?get("SELECT nome FROM motoristas WHERE id=?",[motId])?.nome||'':'';const id=uid(),inicio=new Date().toISOString();run("INSERT INTO percursos(id,maquina_id,maquina_nome,maquina_codigo,operador_id,operador_nome,motorista_id,motorista_nome,inicio,lat_inicio,lng_inicio,endereco_inicio,status)VALUES(?,?,?,?,?,?,?,?,?,?,?,?,'em_andamento')",[id,m.id,m.nome,m.codigo,req.user.uid,req.user.nome,motId,motNome,inicio,lat?+lat:null,lng?+lng:null,String(endereco||'').slice(0,300)]);audit(req,'iniciar_percurso','percurso',id,{maquina_id,maquina:m.nome,lat,lng});res.json(get("SELECT * FROM percursos WHERE id=?",[id]))});
app.post('/api/percursos/encerrar',authMiddleware,(req,res)=>{const{lat,lng,endereco}=req.body;const p=get("SELECT * FROM percursos WHERE operador_id=? AND status='em_andamento'",[req.user.uid]);if(!p)return res.status(404).json({error:'Nenhum percurso em andamento'});const fim=new Date().toISOString(),dur=Math.floor((new Date(fim).getTime()-new Date(p.inicio).getTime())/1000);run("UPDATE percursos SET fim=?,lat_fim=?,lng_fim=?,endereco_fim=?,duracao_seg=?,status='concluido' WHERE id=?",[fim,lat?+lat:null,lng?+lng:null,String(endereco||'').slice(0,300),dur,p.id]);audit(req,'encerrar_percurso','percurso',p.id,{duracao_seg:dur,maquina:p.maquina_nome});res.json(get("SELECT * FROM percursos WHERE id=?",[p.id]))});
app.get('/api/percursos',authMiddleware,adminOnly,(req,res)=>{const{maquina_id,operador_id,status,inicio,fim}=req.query;const limit=safeInt(req.query.limit,200,2000);let sql="SELECT * FROM percursos WHERE 1=1";const p=[];if(maquina_id){sql+=' AND maquina_id=?';p.push(maquina_id)}if(operador_id){sql+=' AND operador_id=?';p.push(operador_id)}if(status){sql+=' AND status=?';p.push(status)}if(inicio){sql+=' AND inicio>=?';p.push(inicio)}if(fim){sql+=' AND inicio<=?';p.push(fim+'T23:59:59')}sql+=' ORDER BY inicio DESC LIMIT ?';p.push(limit);res.json(all(sql,p).map(r=>({...r,duracao_fmt:r.status==='em_andamento'?fmtSeg(Math.floor((Date.now()-new Date(r.inicio).getTime())/1000)):fmtSeg(r.duracao_seg)})))});
app.delete('/api/percursos/:id',authMiddleware,adminOnly,(req,res)=>{const p=get("SELECT * FROM percursos WHERE id=?",[req.params.id]);if(!p)return res.status(404).json({error:'404'});run("DELETE FROM percursos WHERE id=?",[req.params.id]);audit(req,'excluir_percurso','percurso',req.params.id,{maquina:p.maquina_nome,operador:p.operador_nome});res.json({ok:true})});
app.get('/api/percursos/export.csv',authMiddleware,adminOnly,(_,res)=>{const rows=all("SELECT * FROM percursos ORDER BY inicio DESC");const h='Maquina,Codigo,Operador,Motorista,Inicio,Fim,Duracao,Status,LatInicio,LngInicio,EnderecoInicio,LatFim,LngFim,EnderecoFim\n';const csv=h+rows.map(r=>[r.maquina_nome,r.maquina_codigo,r.operador_nome,r.motorista_nome,r.inicio,r.fim,r.status==='em_andamento'?fmtSeg(Math.floor((Date.now()-new Date(r.inicio).getTime())/1000)):fmtSeg(r.duracao_seg),r.status,r.lat_inicio||'',r.lng_inicio||'',r.endereco_inicio||'',r.lat_fim||'',r.lng_fim||'',r.endereco_fim||''].map(v=>`"${String(v??'').replace(/"/g,'""')}"`).join(',')).join('\n');res.setHeader('Content-Disposition','attachment;filename="percursos.csv"');res.setHeader('Content-Type','text/csv;charset=utf-8');res.send('\uFEFF'+csv)});

