app.get('/api/auditoria',authMiddleware,adminOnly,(req,res)=>{const limit=safeInt(req.query.limit,100,500);res.json(all("SELECT * FROM auditoria ORDER BY criado_em DESC LIMIT ?",[limit]))});

// STATS
app.get('/api/stats',authMiddleware,(req,res)=>{const{veiculo_id,inicio,fim}=req.query;let w='WHERE 1=1';const p=[];if(veiculo_id){w+=' AND a.veiculo_id=?';p.push(veiculo_id)}if(inicio){w+=' AND a.data>=?';p.push(inicio)}if(fim){w+=' AND a.data<=?';p.push(fim+'T23:59')}
const geral=get(`SELECT COUNT(*)AS total,COALESCE(SUM(total),0)AS gasto,COALESCE(SUM(litros),0)AS litros,COALESCE(AVG(CASE WHEN consumo>0 THEN consumo END),0)AS media_consumo,COALESCE(AVG(CASE WHEN preco>0 THEN preco END),0)AS preco_medio FROM abastecimentos a ${w}`,p);
const por_mes=all(`SELECT substr(a.data,1,7)AS mes,SUM(a.total)AS total,SUM(a.litros)AS litros,COUNT(*)AS qtd FROM abastecimentos a ${w} GROUP BY mes ORDER BY mes DESC LIMIT 12`,p).reverse();
const por_comb=all(`SELECT a.combustivel,SUM(a.total)AS total,SUM(a.litros)AS litros,COUNT(*)AS qtd FROM abastecimentos a ${w} GROUP BY a.combustivel ORDER BY total DESC`,p);
const por_veiculo=all(`SELECT v.placa,v.nome AS v_nome,v.marca,v.modelo,SUM(a.total)AS total,SUM(a.litros)AS litros,COUNT(*)AS qtd,AVG(CASE WHEN a.consumo>0 THEN a.consumo END)AS media_consumo FROM abastecimentos a JOIN veiculos v ON v.id=a.veiculo_id ${w} AND v.ativo=1 GROUP BY a.veiculo_id ORDER BY total DESC`,p);
const consumo_hist=all(`SELECT substr(a.data,1,10)AS dia,a.consumo,v.placa FROM abastecimentos a LEFT JOIN veiculos v ON v.id=a.veiculo_id ${w} AND a.consumo>0 ORDER BY a.data DESC LIMIT 30`,p).reverse();
const preco_hist=all(`SELECT substr(a.data,1,10)AS dia,a.preco,a.combustivel FROM abastecimentos a ${w} ORDER BY a.data DESC LIMIT 30`,p).reverse();
res.json({geral,por_mes,por_comb,por_veiculo,consumo_hist,preco_hist,fotos_count:get(`SELECT COUNT(*)AS n FROM fotos f JOIN abastecimentos a ON a.id=f.abastecimento_id ${w}`,p)?.n||0,total_veiculos:get('SELECT COUNT(*)AS n FROM veiculos WHERE ativo=1')?.n||0,total_manut:get('SELECT COUNT(*)AS n FROM manutencoes m JOIN veiculos v ON v.id=m.veiculo_id WHERE v.ativo=1')?.n||0,manut_valor:get('SELECT COALESCE(SUM(m.valor),0)AS total FROM manutencoes m JOIN veiculos v ON v.id=m.veiculo_id WHERE v.ativo=1')?.total||0,total_motoristas:get('SELECT COUNT(*)AS n FROM motoristas WHERE ativo=1')?.n||0,alertas_pendentes:get('SELECT COUNT(*)AS n FROM alertas WHERE lido=0 AND resolvido=0')?.n||0})});

app.get('/api/config',authMiddleware,(req,res)=>{const cfg={};all('SELECT chave,valor FROM config').forEach(r=>cfg[r.chave]=r.valor);if(req.user.perfil!=='admin'){delete cfg.smtp_pass;}res.json(cfg)});
const ALLOWED_CONFIG_KEYS=new Set(['empresa','responsavel','alerta_dias_antecedencia','alerta_km_antecedencia','alerta_km_antecedencia_moto','smtp_host','smtp_port','smtp_user','smtp_pass','alerta_email']);
app.post('/api/config',authMiddleware,adminOnly,(req,res)=>{Object.entries(req.body).forEach(([k,v])=>{if(ALLOWED_CONFIG_KEYS.has(k))run('INSERT OR REPLACE INTO config VALUES(?,?)',[k,String(v).slice(0,500)])});res.json({ok:true})});
app.get('/api/export/csv',authMiddleware,(_,res)=>{const rows=all("SELECT a.data,v.placa,v.marca,v.modelo,a.combustivel,a.posto,a.litros,a.preco,a.total,a.hodometro,a.km_rodados,a.consumo,CASE a.cheio WHEN 1 THEN'Sim'ELSE'Nao'END AS cheio,a.nota,a.obs FROM abastecimentos a LEFT JOIN veiculos v ON v.id=a.veiculo_id ORDER BY a.data DESC");const h='Data,Placa,Marca,Modelo,Combustivel,Posto,Litros,Preco,Total,Hodometro,KmRodados,Consumo,Cheio,Nota,Obs\n';const csv=h+rows.map(r=>Object.values(r).map(v=>`"${String(v||'').replace(/"/g,'""')}"`).join(',')).join('\n');res.setHeader('Content-Disposition','attachment;filename="abastecimentos.csv"');res.setHeader('Content-Type','text/csv;charset=utf-8');res.send('\uFEFF'+csv)});

app.get('*',(_,res)=>res.sendFile(path.join(__dirname,'public','index.html')));

